export function getLocationProfile(slug: string): LocationProfile | undefined { return locationProfiles[slug]; }
export function getLocationProfileByName(name: string): LocationProfile | undefined {
  const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  return locationProfiles[slug];
}
export function getAllLocationSlugs(): string[] { return Object.keys(locationProfiles); }
